page.script:
import { asapWeb } from "./asapweb.js";
import { ASAPInfo } from "./asap.js";
let asapFiles;
function populateFiles(contents, mainFilenames)
{
	const select = document.getElementById("fileSelect");
	switch (mainFilenames.length) {
	case 0:
		alert("No supported file selected");
		return;
	case 1:
		select.style.display = "none";
		break;
	default:
		select.innerHTML = "";
		for (const name of mainFilenames)
			select.add(new Option(name));
		select.style.display = "";
		break;
	}
	asapFiles = contents;
	document.getElementById("pauseButton").style.display = "";
	asapWeb.onUpdate = update;
	asapWeb.playContent(mainFilenames[0], contents);
}
function openFiles()
{
	const files = this.files;
	const mainFilenames = [];
	const contents = {};
	let count = files.length;
	for (const file of files) {
		if (ASAPInfo.isOurFile(file.name))
			mainFilenames.push(file.name);
		const reader = new FileReader();
		reader.onload = e => {
			contents[file.name] = new Uint8Array(e.target.result);
			if (--count == 0)
				populateFiles(contents, mainFilenames);
		};
		reader.readAsArrayBuffer(file);
	}
}
function update()
{
	const seekBar = document.getElementById("seekBar");
	seekBar.style.display = "";
	const info = asapWeb.asap.getInfo();
	seekBar.max = info.getDuration(info.getDefaultSong());
	seekBar.value = asapWeb.asap.getPosition();
}
function selectFile()
{
	asapWeb.playContent(this.value, asapFiles);
}
document.getElementById("fileInput").addEventListener("change", openFiles);
document.getElementById("fileSelect").addEventListener("change", selectFile);
document.getElementById("pauseButton").addEventListener("click", () => asapWeb.togglePause());
document.getElementById("seekBar").addEventListener("input", function() { asapWeb.seek(this.value); });
